/**
 * Load API key from secrets.json (Kaya standard pattern)
 */
function loadConfig(): Config {
  const secretsPath = join(homedir(), '.claude', 'secrets.json');

  // First try environment variable (for CI/testing)
  if (process.env.GNEWS_API_KEY) {
    return {
      apiKey: process.env.GNEWS_API_KEY,
      baseUrl: DEFAULTS.baseUrl,
    };
  }

  // Then try secrets.json (Kaya standard)
  try {
    if (!existsSync(secretsPath)) {
      console.error('Error: ~/.claude/secrets.json not found');
      console.error('Create secrets.json with: "GNEWS_API_KEY": "your_key"');
      console.error('Get your free API key at: https://gnews.io/');
      process.exit(1);
    }

    const secretsContent = readFileSync(secretsPath, 'utf-8');
    const secrets = JSON.parse(secretsContent);
    const apiKey = secrets.GNEWS_API_KEY;

    if (!apiKey || apiKey === 'YOUR_GNEWS_API_KEY') {
      console.error('Error: GNEWS_API_KEY not configured in ~/.claude/secrets.json');
      console.error('Add your API key: "GNEWS_API_KEY": "your_actual_key"');
      console.error('Get your free API key at: https://gnews.io/');
      process.exit(1);
    }

    return {
      apiKey,
      baseUrl: DEFAULTS.baseUrl,
    };
  } catch (error) {
    if (error instanceof SyntaxError) {
      console.error('Error: Invalid JSON in ~/.claude/secrets.json');
    } else {
      console.error('Error: Cannot read ~/.claude/secrets.json');
    }
    process.exit(1);
  }
}

// ============================================================================
// API Functions
// ============================================================================

/**
 * Make authenticated request to GNews API
 */
async function fetchGNews(
  config: Config,
  endpoint: string,
  params: Record<string, string>
): Promise<GNewsResponse> {
  const searchParams = new URLSearchParams({
    ...params,
    apikey: config.apiKey,
  });

  const url = `${config.baseUrl}/${endpoint}?${searchParams}`;

  try {
    const response = await fetch(url);

    if (!response.ok) {
      if (response.status === 401) {
        console.error('Error: Invalid API key');
        console.error('Check your GNEWS_API_KEY and try again');
        process.exit(1);
      }
      if (response.status === 403) {
        console.error('Error: API rate limit exceeded or plan limit reached');
        console.error('Free plan: 100 requests/day');
        process.exit(1);
      }
      if (response.status === 429) {
        console.error('Error: Too many requests');
        console.error('Please wait before making more requests');
        process.exit(1);
      }

      const errorText = await response.text();
      console.error(`Error: API request failed (${response.status})`);
      console.error(errorText);
      process.exit(1);
    }

    return (await response.json()) as GNewsResponse;
  } catch (error) {
    if (error instanceof Error) {
      console.error(`Error: Network request failed - ${error.message}`);
    } else {
      console.error('Error: Network request failed');
    }
    process.exit(1);
  }
}

