/**
 * Search for news articles by keyword
 */
async function search(query: string, options: SearchOptions): Promise<void> {
  const config = loadConfig();

  if (!query || query.trim() === '') {
    console.error('Error: Search query is required');
    console.error('Usage: gnews search <query> [options]');
    process.exit(1);
  }

  const params: Record<string, string> = {
    q: query,
    max: (options.max ?? DEFAULTS.max).toString(),
    sortby: options.sortby ?? DEFAULTS.sortby,
  };

  if (options.lang) params.lang = options.lang;
  if (options.country) params.country = options.country;
  if (options.from) params.from = options.from;
  if (options.to) params.to = options.to;
  if (options.in) params.in = options.in;

  const data = await fetchGNews(config, 'search', params);
  console.log(JSON.stringify(data, null, 2));
}

/**
 * Get top headlines
 */
async function topHeadlines(options: TopHeadlinesOptions): Promise<void> {
  const config = loadConfig();

  const params: Record<string, string> = {
    max: (options.max ?? DEFAULTS.max).toString(),
  };

  if (options.category) {
    if (!CATEGORIES.includes(options.category as typeof CATEGORIES[number])) {
      console.error(`Error: Invalid category '${options.category}'`);
      console.error(`Valid categories: ${CATEGORIES.join(', ')}`);
      process.exit(1);
    }
    params.category = options.category;
  }

  if (options.lang) params.lang = options.lang;
  if (options.country) params.country = options.country;
  if (options.query) params.q = options.query;

  const data = await fetchGNews(config, 'top-headlines', params);
  console.log(JSON.stringify(data, null, 2));
}

