// ============================================================================
// Argument Parsing Helpers
// ============================================================================

function getArgValue(args: string[], flag: string): string | undefined {
  const index = args.indexOf(flag);
  if (index !== -1 && args[index + 1] && !args[index + 1].startsWith('-')) {
    return args[index + 1];
  }
  return undefined;
}

function getArgNumber(args: string[], flag: string): number | undefined {
  const value = getArgValue(args, flag);
  if (value) {
    const num = parseInt(value, 10);
    if (isNaN(num) || num <= 0) {
      console.error(`Error: ${flag} must be a positive number`);
      process.exit(1);
    }
    return num;
  }
  return undefined;
}

// ============================================================================
// Main CLI Entry Point
// ============================================================================

async function main() {
  const args = process.argv.slice(2);

  // Handle help/version
  if (args.length === 0 || args[0] === 'help' || args[0] === '--help' || args[0] === '-h') {
    showHelp();
    return;
  }

  if (args[0] === 'version' || args[0] === '--version' || args[0] === '-v') {
    showVersion();
    return;
  }

  const command = args[0];

  // Route to commands
  switch (command) {
    case 'search': {
      const query = args[1];
      if (!query || query.startsWith('-')) {
        console.error('Error: Search query is required');
        console.error('Usage: gnews search <query> [options]');
        process.exit(1);
      }

      const options: SearchOptions = {
        lang: getArgValue(args, '--lang'),
        country: getArgValue(args, '--country'),
        max: getArgNumber(args, '--max'),
        from: getArgValue(args, '--from'),
        to: getArgValue(args, '--to'),
        sortby: getArgValue(args, '--sortby') as 'publishedAt' | 'relevance' | undefined,
        in: getArgValue(args, '--in'),
      };

      await search(query, options);
      break;
    }

    case 'headlines':
    case 'top':
    case 'news': {
      const options: TopHeadlinesOptions = {
        category: getArgValue(args, '--category'),
        lang: getArgValue(args, '--lang'),
        country: getArgValue(args, '--country'),
        max: getArgNumber(args, '--max'),
        query: getArgValue(args, '--query'),
      };

      await topHeadlines(options);
      break;
    }

    case 'categories':
      listCategories();
      break;

    case 'languages':
      listLanguages();
      break;

    case 'countries':
      listCountries();
      break;

    default:
      console.error(`Error: Unknown command '${command}'`);
      console.error('Run "gnews --help" for usage information');
      process.exit(1);
  }
}

// Run CLI
main().catch((error) => {
  console.error('Fatal error:', error);
  process.exit(1);
});
